// Baut aus der Agent-Antwort ($json.output) eine schlichte HTML-Report-Seite.
const item = $input.first().json;

const esc = (s) => String(s ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;');

const auftrag = esc($('Auftrag setzen').first().json.auftrag);
const report = esc(String(item.output ?? '').trim());
const datum = new Date().toLocaleString('de-DE', { dateStyle: 'long', timeStyle: 'short' });

const html = `<!DOCTYPE html>
<html lang="de">
<head><meta charset="utf-8"><title>Markt-Report</title>
<style>
  body { margin:0; padding:48px 24px; background:#fafafa; color:#212121;
    font-family: system-ui, -apple-system, sans-serif; line-height:1.6; }
  .sheet { max-width:760px; margin:0 auto; background:#fff; border:1px solid #e8e8e8;
    border-radius:14px; overflow:hidden; }
  header { background:#212121; color:#fafafa; padding:32px 40px; }
  .eyebrow { text-transform:uppercase; letter-spacing:.14em; font-size:11px;
    color:#87cdcb; margin:0 0 10px; }
  header h1 { margin:0; font-size:26px; font-weight:600; }
  .auftrag { padding:20px 40px; background:#f4fbfb; border-bottom:1px solid #e8e8e8;
    font-size:14px; }
  main { padding:32px 40px; white-space:pre-wrap; font-size:15px; }
  footer { text-align:center; color:#a0a0a0; font-size:11px; padding:20px; }
</style></head>
<body><div class="sheet">
  <header><p class="eyebrow">Recherche-Agent</p><h1>Markt-Report</h1></header>
  <div class="auftrag"><strong>Auftrag:</strong> ${auftrag}</div>
  <main>${report}</main>
  <footer>Erzeugt von n8n · ${datum}</footer>
</div></body></html>`;

const htmlBase64 = Buffer.from(html, 'utf8').toString('base64');
return [{ json: { ...item, html, htmlBase64 } }];
